const sql = require('../models/db');

const NotificationService = {};

NotificationService.createNotification = async ({ userId, type, event, title, message }) => {
  return sql.user_notification.create({
    user_id_fk: userId,
    type,
    event,
    title,
    message,
    unread: true,
    created_date: new Date(),
  });
};

NotificationService.createManyNotifications = async (userIds, { type, event, title, message }) => {
  const records = userIds.map(userId => ({
    user_id_fk: userId,
    type,
    event,
    title,
    message,
    unread: true,
    created_date: new Date(),
  }));
  return sql.user_notification.bulkCreate(records);
};

NotificationService.getNotifications = async (userId, limit = 20) => {
  return sql.user_notification.findAll({
    where: { user_id_fk: userId, unread: true },
    order: [['created_date', 'DESC']],
    limit,
  });
};

NotificationService.getUnreadCount = async (userId) => {
  return sql.user_notification.count({
    where: { user_id_fk: userId, unread: true },
  });
};

NotificationService.markAsRead = async (id, userId) => {
  return sql.user_notification.update(
    { unread: false },
    { where: { id, user_id_fk: userId } }
  );
};

NotificationService.deleteAll = async (userId) => {
  return sql.user_notification.destroy({
    where: { user_id_fk: userId },
  });
};

NotificationService.markAllAsRead = async (userId) => {
  return sql.user_notification.update(
    { unread: false },
    { where: { user_id_fk: userId, unread: true } }
  );
};

// Returns all active users (id, name, lastname, email, profile_photo) for @mention autocomplete.
NotificationService.getMentionableUsers = async () => {
  return sql.users.findAll({
    where: { status: 'active' },
    attributes: ['id', 'name', 'lastname', 'email', 'profile_photo'],
    order: [['name', 'ASC']],
  });
};

module.exports = NotificationService;

