const NotificationService = require('../services/notification.service');
const { getUserInfo } = require('../helpers/auth');

exports.getNotifications = async (req, res) => {
  try {
    const userInfo = await getUserInfo(req.headers.authorization);
    const notifications = await NotificationService.getNotifications(userInfo.user_id);
    res.json({ status: true, data: notifications });
  } catch (err) {
    res.status(500).json({ error: 'SYS-N06', message: err.message });
  }
};

exports.getCount = async (req, res) => {
  try {
    const userInfo = await getUserInfo(req.headers.authorization);
    const count = await NotificationService.getUnreadCount(userInfo.user_id);
    res.json({ count });
  } catch (err) {
    res.status(500).json({ error: 'SYS-N01', message: err.message });
  }
};

exports.createNotification = async (req, res) => {
  try {
    const { userId, type, event, title, message } = req.body;
    const notification = await NotificationService.createNotification({ userId, type, event, title, message });
    res.json({ status: true, data: notification });
  } catch (err) {
    res.status(500).json({ error: 'SYS-N02', message: err.message });
  }
};

exports.markAsRead = async (req, res) => {
  try {
    const userInfo = await getUserInfo(req.headers.authorization);
    await NotificationService.markAsRead(req.params.id, userInfo.user_id);
    res.json({ status: true });
  } catch (err) {
    res.status(500).json({ error: 'SYS-N03', message: err.message });
  }
};

exports.markAllAsRead = async (req, res) => {
  try {
    const userInfo = await getUserInfo(req.headers.authorization);
    await NotificationService.markAllAsRead(userInfo.user_id);
    res.json({ status: true });
  } catch (err) {
    res.status(500).json({ error: 'SYS-N04', message: err.message });
  }
};

exports.deleteAll = async (req, res) => {
  try {
    const userInfo = await getUserInfo(req.headers.authorization);
    const deleted = await NotificationService.deleteAll(userInfo.user_id);
    res.json({ status: true, deleted });
  } catch (err) {
    res.status(500).json({ error: 'SYS-N07', message: err.message });
  }
};

exports.getMentionableUsers = async (req, res) => {
  try {
