  });

  // ── createNotification ────────────────────────────────────────────────────

  describe('createNotification', () => {
    test('calls create with correct fields and unread=true', async () => {
      mockUserNotification.create.mockResolvedValue({ id: 1 });
      const payload = { userId: 42, type: 'mention', event: 'rfq', title: 'Hi', message: 'You were mentioned' };
      const result = await NotificationService.createNotification(payload);
      expect(mockUserNotification.create).toHaveBeenCalledWith(
        expect.objectContaining({
          user_id_fk: 42,
          type: 'mention',
          event: 'rfq',
          title: 'Hi',
          message: 'You were mentioned',
          unread: true,
        })
      );
      expect(result).toEqual({ id: 1 });
    });

    test('sets created_date on creation', async () => {
      mockUserNotification.create.mockResolvedValue({ id: 2 });
      await NotificationService.createNotification({ userId: 1, type: 't', event: 'e', title: 't', message: 'm' });
      const callArg = mockUserNotification.create.mock.calls[0][0];
      expect(callArg.created_date).toBeInstanceOf(Date);
    });
  });

  // ── createManyNotifications ───────────────────────────────────────────────

  describe('createManyNotifications', () => {
    test('bulk creates one record per userId', async () => {
      mockUserNotification.bulkCreate.mockResolvedValue([]);
      await NotificationService.createManyNotifications([1, 2, 3], { type: 'task_assignment', event: 'rfq', title: 'T', message: 'M' });
      const records = mockUserNotification.bulkCreate.mock.calls[0][0];
      expect(records).toHaveLength(3);
      expect(records[0].user_id_fk).toBe(1);
      expect(records[2].user_id_fk).toBe(3);
      records.forEach(r => expect(r.unread).toBe(true));
    });
  });

  // ── getNotifications ──────────────────────────────────────────────────────

  describe('getNotifications', () => {
    test('queries unread notifications for user ordered by created_date DESC', async () => {
      const rows = [{ id: 10, title: 'A' }, { id: 9, title: 'B' }];
      mockUserNotification.findAll.mockResolvedValue(rows);
      const result = await NotificationService.getNotifications(42);
      expect(mockUserNotification.findAll).toHaveBeenCalledWith({
        where: { user_id_fk: 42, unread: true },
        order: [['created_date', 'DESC']],
        limit: 20,
      });
      expect(result).toEqual(rows);
    });

    test('respects custom limit parameter', async () => {
      mockUserNotification.findAll.mockResolvedValue([]);
      await NotificationService.getNotifications(1, 5);
      expect(mockUserNotification.findAll).toHaveBeenCalledWith(
        expect.objectContaining({ limit: 5 })
      );
    });
  });

  // ── getUnreadCount ────────────────────────────────────────────────────────

  describe('getUnreadCount', () => {
    test('counts unread notifications for user', async () => {
      mockUserNotification.count.mockResolvedValue(3);
      const result = await NotificationService.getUnreadCount(7);
      expect(mockUserNotification.count).toHaveBeenCalledWith({
        where: { user_id_fk: 7, unread: true },
      });
      expect(result).toBe(3);
    });
  });

  // ── markAsRead ────────────────────────────────────────────────────────────

  describe('markAsRead', () => {
    test('sets unread=false for matching id and userId', async () => {
      mockUserNotification.update.mockResolvedValue([1]);
      await NotificationService.markAsRead(5, 42);
      expect(mockUserNotification.update).toHaveBeenCalledWith(
        { unread: false },
        { where: { id: 5, user_id_fk: 42 } }
      );
    });
  });

  // ── markAllAsRead ─────────────────────────────────────────────────────────

  describe('markAllAsRead', () => {
    test('sets unread=false for all user notifications', async () => {
      mockUserNotification.update.mockResolvedValue([4]);
      await NotificationService.markAllAsRead(42);
      expect(mockUserNotification.update).toHaveBeenCalledWith(
        { unread: false },
        { where: { user_id_fk: 42, unread: true } }
      );
    });
  });

  // ── deleteAll ─────────────────────────────────────────────────────────────

  describe('deleteAll', () => {
    test('destroys all notifications for user', async () => {
      mockUserNotification.destroy.mockResolvedValue(7);
      const result = await NotificationService.deleteAll(42);
      expect(mockUserNotification.destroy).toHaveBeenCalledWith({
        where: { user_id_fk: 42 },
      });
      expect(result).toBe(7);
    });

    test('only deletes notifications belonging to the requesting user', async () => {
      mockUserNotification.destroy.mockResolvedValue(0);
      await NotificationService.deleteAll(99);
      const callArg = mockUserNotification.destroy.mock.calls[0][0];
      expect(callArg.where.user_id_fk).toBe(99);
      expect(Object.keys(callArg.where)).toEqual(['user_id_fk']);
    });
  });
