import { Injectable, OnDestroy } from '@angular/core';
import { HttpClient, HttpHeaders } from '@angular/common/http';
import { BehaviorSubject, interval, Subscription } from 'rxjs';
import { startWith, switchMap } from 'rxjs/operators';
import { environment } from 'src/environments/environment';

export interface MentionableUser {
  id: number;
  name: string;
  lastname: string;
  email: string;
  profile_photo: string | null;
}

export interface NotificationItem {
  id: number;
  type: string;
  event: string;
  title: string;
  message: string;
  unread: boolean;
  created_date: string;
}

export interface CreateNotificationPayload {
  userId: number;
  type: string;
  event: string;
  title: string;
  message: string;
}

@Injectable({ providedIn: 'root' })
export class NotificationService implements OnDestroy {
  private readonly base = `${environment.url}/api/notifications`;
  private readonly POLL_INTERVAL_MS = 30_000;

  private readonly _unreadCount = new BehaviorSubject<number>(0);
  readonly unreadCount$ = this._unreadCount.asObservable();

  private _pollSub: Subscription | null = null;

  constructor(private readonly http: HttpClient) {}

  private headers(): HttpHeaders {
    const token = localStorage.getItem('token');
    return token ? new HttpHeaders().set('Authorization', token) : new HttpHeaders();
  }

  /** Begin polling the unread count every 30 s. No-ops if already polling. */
  startPolling(): void {
    if (this._pollSub) return;
    this._pollSub = interval(this.POLL_INTERVAL_MS)
      .pipe(
        startWith(0),
        switchMap(() =>
          this.http.get<{ count: number }>(`${this.base}/count`, { headers: this.headers() })
        )
      )
      .subscribe({
        next: ({ count }) => this._unreadCount.next(count),
        error: () => {},
      });
  }

  stopPolling(): void {
    this._pollSub?.unsubscribe();
    this._pollSub = null;
  }

  /** Force a one-shot refresh of the unread count (e.g. after marking as read). */
  refreshCount(): void {
    this.http
      .get<{ count: number }>(`${this.base}/count`, { headers: this.headers() })
      .subscribe({ next: ({ count }) => this._unreadCount.next(count), error: () => {} });
  }

  getNotifications() {
    return this.http.get<{ status: boolean; data: NotificationItem[] }>(
      `${this.base}`,
      { headers: this.headers() }
    );
  }

  markAsRead(id: number) {
    return this.http.patch<{ status: boolean }>(`${this.base}/${id}/read`, {}, { headers: this.headers() });
  }

  markAllAsRead() {
    return this.http.post<{ status: boolean }>(`${this.base}/read-all`, {}, { headers: this.headers() });
  }

  deleteAll() {
    return this.http.delete<{ status: boolean; deleted: number }>(
      `${this.base}`,
      { headers: this.headers() }
    );
  }

  getMentionableUsers() {
    return this.http.get<{ status: boolean; data: MentionableUser[] }>(
      `${this.base}/mentionable-users`,
      { headers: this.headers() }
    );
  }

  createNotification(payload: CreateNotificationPayload) {
    return this.http.post<{ status: boolean; data: any }>(
      `${this.base}/create`,
      payload,
      { headers: this.headers() }
    );
  }

  ngOnDestroy(): void {
    this.stopPolling();
  }
}

