import {
  Component,
  ElementRef,
  EventEmitter,
  Input,
  OnDestroy,
  OnInit,
  Output,
  ViewChild,
} from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import { Subscription } from 'rxjs';
import {
  MentionableUser,
  NotificationService,
} from 'src/app/helpers/services/notification.service';

@Component({
  selector: 'comment-form',
  templateUrl: './comment-form.component.html',
  styleUrls: ['./comment-form.component.scss'],
  standalone: false,
})
export class CommentFormComponent implements OnInit, OnDestroy {
  @Input() submitLabel!: string;
  @Input() hasCancelButton = false;
  @Input() initialText = '';
  @Input() comment: string;

  @Output() handleSubmit = new EventEmitter<{ text: string; files?: any[] }>();
  @Output() handleCancel = new EventEmitter<void>();

  @ViewChild('fileInput') fileInput: ElementRef;

  form!: FormGroup;
  files: any[] = [];

  // @mention state
  quillEditor: any = null;
  mentionUsers: MentionableUser[] = [];
  filteredMentionUsers: MentionableUser[] = [];
  showMentionPicker = false;
  mentionStart = -1;
  mentionPartial = '';

  private mentionSub: Subscription | null = null;

  constructor(
    private fb: FormBuilder,
    private notificationService: NotificationService
  ) {}

  ngOnInit(): void {
    this.form = this.fb.group({
      title: [this.initialText, Validators.required],
    });

    this.mentionSub = this.notificationService
      .getMentionableUsers()
      .subscribe({
        next: (res) => { this.mentionUsers = res?.data ?? []; },
        error: () => {},
      });
  }

  ngOnDestroy(): void {
    this.mentionSub?.unsubscribe();
  }

  onEditorCreated(editor: any): void {
    this.quillEditor = editor;
  }

  onContentChanged(event: any): void {
    const editor = event.editor;
    const selection = editor.getSelection();
    if (!selection) { this.closeMention(); return; }

    const text: string = editor.getText();
    const textBefore = text.substring(0, selection.index);
    const atIndex = textBefore.lastIndexOf('@');

    if (atIndex === -1) { this.closeMention(); return; }

    const partial = textBefore.substring(atIndex + 1);
    // A space after @ means the mention token is done
    if (/[\s\n]/.test(partial)) { this.closeMention(); return; }

    this.mentionStart = atIndex;
    this.mentionPartial = partial;
    this.filteredMentionUsers = this.filterUsers(partial);
    this.showMentionPicker = this.filteredMentionUsers.length > 0;
  }

  onMentionPicked(user: MentionableUser): void {
    if (!this.quillEditor) return;
    const selection = this.quillEditor.getSelection();
    const cursorIndex =
      selection?.index ?? this.mentionStart + this.mentionPartial.length + 1;

    // Replace from '@' to cursor with the resolved mention handle
    this.quillEditor.deleteText(this.mentionStart, cursorIndex - this.mentionStart);
    const insertText = `@${user.name} `;
    this.quillEditor.insertText(this.mentionStart, insertText, 'user');
    this.quillEditor.setSelection(this.mentionStart + insertText.length);
    this.closeMention();
  }

  closeMention(): void {
    this.showMentionPicker = false;
    this.filteredMentionUsers = [];
  }

  private filterUsers(partial: string): MentionableUser[] {
    if (!partial) return this.mentionUsers.slice(0, 8);
    const q = partial.toLowerCase();
    return this.mentionUsers
      .filter(
        (u) =>
          (u.name ?? '').toLowerCase().startsWith(q) ||
          (u.lastname ?? '').toLowerCase().startsWith(q) ||
          `${u.name ?? ''} ${u.lastname ?? ''}`.toLowerCase().includes(q)
      )
      .slice(0, 8);
  }

  onFileSelected(event: any): void {
    this.files = [];
    this.files = event.target.files;
  }

  onSubmit(): void {
    this.handleSubmit.emit({ text: this.form.value.title, files: this.files });
    this.form.reset();
    this.closeMention();
  }

  resetFileInput(): void {
    if (this.fileInput?.nativeElement) {
      this.fileInput.nativeElement.value = '';
    }
  }
}

