// Extract @handles from comment text. Supports @FirstName and @FirstName.LastName.
function parseMentions(text) {
  if (!text || typeof text !== 'string') return [];
  const matches = text.match(/@([A-Za-z][A-Za-z0-9._-]*)/g) || [];
  return [...new Set(matches.map(m => m.slice(1).toLowerCase()))];
}

// Resolve parsed handles to user IDs by matching against name / name.lastname.
function resolveMentions(handles, users) {
  if (!handles.length || !users.length) return [];
  const matchedIds = new Set();
  for (const handle of handles) {
    for (const user of users) {
      const first = (user.name || '').toLowerCase();
      const full = `${user.name || ''}.${user.lastname || ''}`.toLowerCase();
      if (handle === first || handle === full) matchedIds.add(user.id);
    }
  }
  return [...matchedIds];
}

module.exports = { parseMentions, resolveMentions };

