const CommentService = require("../services/comment.service")
const NotificationService = require("../services/notification.service")
const { getUserInfo } = require("../helpers/auth")
const { parseMentions, resolveMentions } = require("../helpers/mention")

const getComment = async (req, res) => {
    const result = await CommentService.getComments(req.params.id);
    res.json(result);
}

const addComment = async (req, res) => {
    const data = await CommentService.addComment(req.body);
    res.json(data);

    // Fire @mention notifications asynchronously — do not delay the response.
    const commentText = req.body.comment;
    const handles = parseMentions(commentText);
    if (handles.length) {
        try {
            const author = await getUserInfo(req.headers.authorization);
            const allUsers = await NotificationService.getMentionableUsers();
            const mentionedIds = resolveMentions(handles, allUsers);
            // Exclude the author from their own mention notifications.
            const targets = mentionedIds.filter(id => id !== author.user_id);
            if (targets.length) {
                const authorName = `${author.name || ''}`.trim() || author.email || 'Someone';
                await NotificationService.createManyNotifications(targets, {
                    type: 'mention',
                    event: 'comment_mention',
                    title: `${authorName} mentioned you`,
                    message: commentText.length > 200 ? commentText.slice(0, 197) + '...' : commentText,
                });
            }
        } catch (err) {
            // Non-fatal — log but don't affect the already-sent response.
            console.error('[mention notification error]', err.message);
        }
    }
}

const updateComment = async (req, res) => {
    const result = await CommentService.updateComment(req.params.id, req.body);
    res.json(result);
}

const deleteComment = async (req, res) => {
    const result = await CommentService.deleteComment(req.params.id);
    res.json(result);
}

module.exports = { getComment, addComment, updateComment, deleteComment }

