  loadAlerts(): void {
    this.alertsLoading = true;
    this.mainService.getnotifications().subscribe({
      next: (res: any) => {
        this.allAlerts = (res?.data || []) as AlertNotification[];
        this.alertsLoading = false;
      },
      error: () => {
        this.allAlerts = [];
        this.alertsLoading = false;
      },
    });
  }

  get unreadAlertCount(): number {
    return this.allAlerts.filter(a => a.unread).length;
  }

