    await firstValueFrom(this.notificationService.markAllAsRead());
    this.allAlerts.forEach(a => (a.unread = false));
    this.notificationService.refreshCount();
  }

  async clearAllAlerts(): Promise<void> {
    await firstValueFrom(this.notificationService.deleteAll());
    this.allAlerts = [];
    this.notificationService.refreshCount();
  }

  getAlertIcon(type: string): string {
    if (type === 'mention') return 'alternate_email';
    if (type === 'task_assignment') return 'assignment_ind';
    return 'notifications';
  }

  // --- Licensing ---

  loadNotifications(): void {
    this.loading = true;
    this.itemDetailService.getNotifications().subscribe({
      next: (data) => {
        this.allNotifications = data || [];
        this.availableStatuses = [...new Set(
          this.allNotifications.map(n => n.status).filter(Boolean)
        )].sort();
        this.currentPage = 1;
        this.loading = false;
      },
      error: () => {
        this.allNotifications = [];
        this.loading = false;
      }
    });
  }

  get filteredNotifications(): LicensingNotification[] {
    let list = this.allNotifications;

    if (this.selectedStatus) {
      list = list.filter(n => n.status === this.selectedStatus);
    }

    if (this.searchText.trim()) {
      const q = this.searchText.toLowerCase().trim();
      list = list.filter(n =>
        (n.item_num_id && String(n.item_num_id).toLowerCase().includes(q)) ||
        (n.item_descr_name && String(n.item_descr_name).toLowerCase().includes(q)) ||
        (n.feedback && String(n.feedback).toLowerCase().includes(q)) ||
        (n.itemheader_id_fk && String(n.itemheader_id_fk).toLowerCase().includes(q)) ||
        (this.getAssignorName(n).toLowerCase().includes(q))
      );
    }

    return list;
  }

  get paginatedNotifications(): LicensingNotification[] {
    const start = (this.currentPage - 1) * this.pageSize;
    return this.filteredNotifications.slice(start, start + this.pageSize);
  }

