    const buildCondition = (filterDef, dbField) => {
      const value = (filterDef && typeof filterDef.filter === 'string') ? filterDef.filter : '';
      // Support multi-tag search for 'tags' field: split by comma/space and AND-match all terms
      if (dbField === 'tags' && value) {
        const terms = value.split(/[\s,]+/).map(s => s.trim()).filter(Boolean);
        if (terms.length > 1) {
          return { [Op.or]: terms.map(t => ({ [Op.iLike]: `%${t}%` })) };
        }
      }
      switch (filterDef.type) {
        case 'contains': return { [Op.iLike]: `%${value}%` };
        case 'notContains': return { [Op.notILike]: `%${value}%` };
        case 'equals': return { [Op.eq]: filterDef.filter };
        case 'notEqual': return { [Op.ne]: filterDef.filter };
        case 'startsWith': return { [Op.iLike]: `${value}%` };
        case 'endsWith': return { [Op.iLike]: `%${value}` };
        default: return null;
      }
    };

    // 🔹 Process filters
    Object.entries(filters).forEach(([field, filterDef]) => {
      if (!filterDef || !filterDef.filter) return;
      const dbField = mapFieldToColumn(field);

      // Special handling: tags filter should also search item description (item_descr_name)
      if (dbField === 'tags') {
        const raw = typeof filterDef.filter === 'string' ? filterDef.filter : String(filterDef.filter || '');
        const terms = raw.split(/[\s,]+/).map(s => s.trim()).filter(Boolean);
        if (terms.length > 0) {
          terms.forEach(term => {
            tagsConditions.push({
              [Op.or]: [
                { tags: { [Op.iLike]: `%${term}%` } },
                { item_descr_name: { [Op.iLike]: `%${term}%` } }
              ]
            });
          });
        }
        return; // handled
      }

      const condition = buildCondition(filterDef, dbField);
      if (!condition) return;

      // Route to correct merch group or itemHeader
      const match = dbField.match(/^merchGroup0([1-6])/);
      if (match) {
        const key = `merchGroup0${match[1]}`;
        merchGroupFilters[key] = condition;
      } else {
        whereClause[dbField] = condition;
      }
    });

    // 🔹 Combine division codes and tags conditions properly (AND them together)
    const andConditions = [];
    const divisionCodeIds = req.query.divisionCodeIds ? JSON.parse(req.query.divisionCodeIds) : [];
    if (divisionCodeIds.length > 0) {
      divisionCodeIds.push(2);
      andConditions.push({
        [Op.or]: [
