        ]
      });
    }

    if (tagsConditions.length > 0) {
      andConditions.push({
        [Op.or]: tagsConditions
      });
    }

    if (andConditions.length > 0) {
      whereClause[Op.and] = andConditions;
    }

    // 🔹 Helper: Generate merchGroup includes
    const generateMerchGroupIncludes = () => {
      return Object.entries(merchGroupFilters).map(([key, filter]) => {
        const match = key.match(/^merchGroup0([1-6])/);
        const hasFilter = Reflect.ownKeys(filter).length > 0;
        return {
          model: sql.merchGroup,
          as: key,
          required: hasFilter,
          where: hasFilter ? { mgTypeCode: `0${match[1]}`, mg_desc: filter, divisionCode_id_fk: divisionCodeIds } : undefined
        }
    }
    );
    };

    const merchIncludes = generateMerchGroupIncludes();

    // 🔹 Query 1: Accurate Count
