ItemLibrary.searchItemTypes = async (req, result) => {
  try {
    const query = String(req.query.q || '').trim();
    const whereClause = buildItemTypeSearchWhereClause(query);
    let itemTypes = await sql.itemType.findAll({
      attributes: ITEM_TYPE_SEARCH_ATTRIBUTES,
      where: whereClause,
      order: [['item_type_name', 'ASC']],
      limit: ITEM_TYPE_SEARCH_LIMIT
    });

    let candidates = itemTypes.map((itemType) => itemType.toJSON());

    if (query) {
      candidates = candidates.sort((left, right) => {
        const scoreDifference = scoreItemTypeCandidate(right, query) - scoreItemTypeCandidate(left, query);
        if (scoreDifference !== 0) {
          return scoreDifference;
        }

        return (left?.item_type_name || '').localeCompare(right?.item_type_name || '');
      });
    }

    result(null, candidates.slice(0, ITEM_TYPE_SEARCH_LIMIT));
  } catch (err) {
    result(null, err);
  }
};

ItemLibrary.createItemType = async (req, result) => {
  try {
    const userInfo = await getUserInfo(req.headers.authorization);
    const itemTypeName = String(req.body.item_type_name || '').trim();
    const itemTypeDescription = String(req.body.item_type_description || '').trim();
    const itemTypeImgThumbnail = String(req.body.item_type_img_thumbnail || '').trim();
    const itemTypeImgFullsize = String(req.body.item_type_img_fullsize || '').trim();

    if (!itemTypeName || !itemTypeDescription || !itemTypeImgThumbnail || !itemTypeImgFullsize) {
      return result(null, { statusCode: 400, message: 'Missing required fields.' });
    }

    const existingItemType = await sql.itemType.findOne({
      where: Sequelize.where(
        Sequelize.fn('lower', Sequelize.col('item_type_name')),
        itemTypeName.toLowerCase()
      )
    });

    if (existingItemType) {
      return result(null, { statusCode: 409, message: 'Item type already exists.' });
    }

    const createdItemType = await sql.itemType.create({
      item_type_name: itemTypeName,
      item_type_description: itemTypeDescription,
      item_type_img_thumbnail: itemTypeImgThumbnail,
      item_type_img_fullsize: itemTypeImgFullsize,
      item_type_status: 'ACTIVE',
      created_user_fk: userInfo?.name,
      created_time_date: new Date()
    });

    result(null, { statusCode: 200, data: createdItemType });
  } catch (err) {
    result(null, err);
  }
};

