async function sendLicensingTeamsNotifications({ payload, userInfo, itemIdentifier, itemDescription, itemNum }) {
  const actorName = userInfo?.name || "Someone";
  await notifyLicensingAssignee({
    itemheaderIdFk: payload.itemheader_id_fk,
    assigneeId: payload.assignee_id,
    assignor: actorName,
    itemIdentifier,
    itemNum,
    itemDescription,
    status: payload.status
  });

  await notifyLicensingTaggedGroup({
    itemheaderIdFk: payload.itemheader_id_fk,
    taggedGroupId: payload.tagged_group_id,
    tagger: actorName,
    itemIdentifier,
    itemNum,
    itemDescription,
    comment: payload.feedback,
    status: payload.status
  });
}

