  models.GridAccessLevel.hasMany(models.GridLayout, { foreignKey: 'col_id', sourceKey: 'col_id' });

  // Define associations for licensingStatus
  models.licensingStatus.belongsTo(models.users, { as: 'assignee', foreignKey: 'assignee_id' });
  models.licensingStatus.belongsTo(models.users, { as: 'assignor', foreignKey: 'assignor_id' });

  if (models.groups && models.licensingStatus) {
      models.groups.hasMany(models.licensingStatus, { as: 'licensingStatuses', foreignKey: 'tagged_group_id' });
      models.licensingStatus.belongsTo(models.groups, { as: 'taggedGroup', foreignKey: 'tagged_group_id' });
  }

  // Define associations for all 10 merchGroup relationships
