const { describe, test, expect, beforeEach } = require('@jest/globals');

jest.mock('sequelize', () => ({}), { virtual: true });

describe('ProductAssignmentService', () => {
  let ProductAssignmentService;
  let mockAssignment;
  let mockItemHeader;
  let mockUsers;

  beforeEach(() => {
    jest.resetModules();

    mockAssignment = {
      findAll: jest.fn(),
      findOne: jest.fn(),
      create: jest.fn(),
      destroy: jest.fn(),
    };
    mockItemHeader = {
      findByPk: jest.fn(),
    };
    mockUsers = {
      findByPk: jest.fn(),
    };

    jest.mock('../../models/db', () => ({
      productUserAssignment: mockAssignment,
      itemHeader: mockItemHeader,
      users: mockUsers,
    }));

    ProductAssignmentService = require('../../services/product_assignment.service');
  });

  test('exposes the five product assignment roles', () => {
    expect(ProductAssignmentService.roles).toEqual([
      'creative_designer',
      'creative_director',
      'technical_designer',
      'licensing_person',
      'salesperson',
    ]);
  });

  test('gets assignments with user profile data', async () => {
    mockAssignment.findAll.mockResolvedValue([{ id: 1 }]);

    const result = await ProductAssignmentService.getAssignments(42);

    expect(mockAssignment.findAll).toHaveBeenCalledWith({
      where: { item_id_fk: 42 },
      include: [{
        model: mockUsers,
        as: 'user',
        attributes: ['id', 'name', 'lastname', 'email', 'profile_photo', 'level'],
      }],
      order: [['role', 'ASC']],
    });
    expect(result).toEqual([{ id: 1 }]);
  });

  test('creates a new assignment when no role row exists', async () => {
    mockItemHeader.findByPk.mockResolvedValue({ item_id_pk: 42 });
    mockUsers.findByPk.mockResolvedValue({ id: 9 });
    mockAssignment.findOne.mockResolvedValue(null);
    mockAssignment.create.mockResolvedValue({ id: 1 });
    mockAssignment.findAll.mockResolvedValue([]);

    await ProductAssignmentService.setAssignments(
      42,
      [{ role: 'creative_designer', userId: 9 }],
      7
    );

    expect(mockAssignment.create).toHaveBeenCalledWith(
      expect.objectContaining({
        item_id_fk: 42,
        role: 'creative_designer',
        user_id_fk: 9,
        created_by_fk: 7,
        updated_by_fk: 7,
      })
    );
  });

  test('updates an existing assignment for the same role', async () => {
    const existing = { update: jest.fn().mockResolvedValue({ id: 1 }) };
    mockItemHeader.findByPk.mockResolvedValue({ item_id_pk: 42 });
    mockUsers.findByPk.mockResolvedValue({ id: 10 });
    mockAssignment.findOne.mockResolvedValue(existing);
    mockAssignment.findAll.mockResolvedValue([]);

    await ProductAssignmentService.setAssignments(
      42,
      { salesperson: 10 },
      7
    );

    expect(existing.update).toHaveBeenCalledWith(
      expect.objectContaining({
        user_id_fk: 10,
        updated_by_fk: 7,
      })
    );
    expect(mockAssignment.create).not.toHaveBeenCalled();
  });

  test('clears a role when user is null', async () => {
    mockItemHeader.findByPk.mockResolvedValue({ item_id_pk: 42 });
    mockAssignment.findAll.mockResolvedValue([]);

    await ProductAssignmentService.setAssignments(
      42,
      [{ role: 'technical_designer', userId: null }],
      7
    );

    expect(mockAssignment.destroy).toHaveBeenCalledWith({
      where: {
        item_id_fk: 42,
        role: 'technical_designer',
      },
    });
  });

  test('rejects unknown roles', async () => {
    mockItemHeader.findByPk.mockResolvedValue({ item_id_pk: 42 });

    await expect(
      ProductAssignmentService.setAssignments(42, [{ role: 'buyer', userId: 1 }])
    ).rejects.toThrow('Invalid product assignment role: buyer');
  });
});

