})
export class ItemLibraryService {
  serverAddress = environment.item_master + '/lib';
  constructor(private http: HttpClient) {
  }
  setUserAuth() {
    let token = localStorage.getItem("token")
    const headers = new HttpHeaders()
      .set('Authorization', token)
    return headers
  }

  setUserAuthWithLoader() {
    let token = localStorage.getItem("token")
    const headers = new HttpHeaders()
      .set('Authorization', token)
      .set('X-Enable-Loader', 'true')
    return headers
  }

  getAllitems(pagination: { startRow?: number, endRow?: number, isArchive: boolean, filterModel?: any, divisionCodeIds?: number[] }) {
    // Set defaults in the service method
    const startRow = pagination.startRow ?? 0
    const endRow = pagination.endRow ?? 100
    const isArchive = pagination.isArchive
    const filterModel = pagination.filterModel
    const divisionCodeIds = pagination.divisionCodeIds

    const params = new HttpParams()
      .set('startRow', startRow.toString())
      .set('endRow', endRow.toString())
      .set('isArchive', isArchive.toString())
      .set('filterModel', JSON.stringify(filterModel))
      .set('divisionCodeIds', JSON.stringify(divisionCodeIds))

    return this.http.get(`${this.serverAddress}/getAllitems`, {
      headers: this.setUserAuthWithLoader(),
      params
    });
  }

  getViewlayout(grid_id) {
    return this.http.get(`${this.serverAddress}/getViewlayout/${grid_id}`, { headers: this.setUserAuth() })
  }
  updateProdOrderHeader(data) {
    return this.http.post(this.serverAddress + '/updateProdOrderHeader', data, { headers: this.setUserAuth() })
  }
  createItem(data) {
    return this.http.post(this.serverAddress + '/createItem', data, { headers: this.setUserAuth() })
  }
  getItemTypes() {
    return this.http.get(`${this.serverAddress}/getItemTypes`, { headers: this.setUserAuth() })
  }
  searchItemTypes(query: string) {
    const params = new HttpParams().set('q', query ?? '')
    return this.http.get(`${this.serverAddress}/searchItemTypes`, {
      headers: this.setUserAuth(),
      params
    })
  }
  createItemType(data) {
    return this.http.post(`${this.serverAddress}/createItemType`, data, { headers: this.setUserAuth() })
  }
  getItemByNumber(itemNumber: string){
    return this.http.get(`${this.serverAddress}/getItemByNumber/${itemNumber}`, { headers: this.setUserAuth() })
  }

  getItemsByDsnRefNum(dsnRefNum: string) {
    return this.http.get(`${this.serverAddress}/getItemsByDsnRefNum/${dsnRefNum}`, { headers: this.setUserAuth() });
  }

  /** Permanent delete of art pieces (item-master `/artPiece/delete`). Mirrors artPieceService.deleteArtPieces. */
  deleteArtPieces(ids: number[]) {
    const artPieceBase = environment.item_master + '/artPiece';
    return this.http.post(`${artPieceBase}/delete`, { ids }, { headers: this.setUserAuth() });
  }

}

